const raw = $json["Email Content"] || "";

// Extract email after "Email:"
const emailMatch = raw.match(/Email:([^\n\r]+)/i);

const email = emailMatch
  ? emailMatch[1].trim()
  : "";

// Extract everything after "Content:"
const contentMatch = raw.match(/Content:([\s\S]*)/i);

const content = contentMatch
  ? contentMatch[1].trim()
  : raw;

return [
  {
    json: {
      email,
      content
    }
  }
];

const form = $json.body.form_response;

// Create field ID -> title map
const fieldMap = {};

for (const field of form.definition.fields) {
  fieldMap[field.id] = field.title;
}

const parsed = {};

for (const answer of form.answers) {

  const key = fieldMap[answer.field.id];

  if (answer.text !== undefined) {
    parsed[key] = answer.text;
  }
  else if (answer.email !== undefined) {
    parsed[key] = answer.email;
  }
  else if (answer.phone_number !== undefined) {
    parsed[key] = answer.phone_number;
  }
  else if (answer.number !== undefined) {
    parsed[key] = answer.number;
  }
  else if (answer.url !== undefined) {
    parsed[key] = answer.url;
  }
  else if (answer.boolean !== undefined) {
    parsed[key] = answer.boolean;
  }
  else if (answer.choice) {
    parsed[key] = answer.choice.label;
  }
  else if (answer.choices) {
    parsed[key] = answer.choices.labels.join(", ");
  }
  else if (answer.date !== undefined) {
    parsed[key] = answer.date;
  }
}

const email = parsed["Email Address"] || "";

const content = Object.entries(parsed)
  .filter(([key]) => key !== "Email Address")
  .map(([key, value]) => `${key}: ${value}`)
  .join("\n");

return [
  {
    json: {
      email,
      content
    }
  }
];

// Get AI text output
const aiText = $json.content.parts[0].text;

// Convert string JSON into object
const data = JSON.parse(aiText);


// Extract ratings
const skills = Number(data.skills_rating);
const experience = Number(data.experience_rating);
const communication = Number(data.communication_rating);
const motivation = Number(data.motivation_rating);


// Weighting system
const weights = {
  skills: 0.4,
  experience: 0.3,
  communication: 0.2,
  motivation: 0.1
};


// Calculate weighted scores
const skills_score = skills * 10 * weights.skills;
const experience_score = experience * 10 * weights.experience;
const communication_score = communication * 10 * weights.communication;
const motivation_score = motivation * 10 * weights.motivation;


// Total score
const total_score =
  skills_score +
  experience_score +
  communication_score +
  motivation_score;


// Recommendation
let recommendation;

if (total_score >= 80) {
  recommendation = "Strongly Recommended";
} 
else if (total_score >= 65) {
  recommendation = "Recommended";
} 
else if (total_score >= 50) {
  recommendation = "Needs Review";
} 
else {
  recommendation = "Not Recommended";
}


// Return final record

return [
  {
    json: {
      ...data,

      skills_score: Number(skills_score.toFixed(2)),
      experience_score: Number(experience_score.toFixed(2)),
      communication_score: Number(communication_score.toFixed(2)),
      motivation_score: Number(motivation_score.toFixed(2)),

      total_score: Number(total_score.toFixed(2)),

      recommendation,

      date_applied: new Date().toISOString()
    }
  }
];

